class NestedIterator {
public:
    NestedIterator(vector<NestedInteger> &nestedList) {
        flatten(nestedList);
    }

    int next() {
        return vals.front(), vals.pop_front();
    }

    bool hasNext() {
        return !vals.empty();
    }

private:
    list<int> vals;
    void flatten(vector<NestedInteger> &nestedList) {
        for (auto &ni : nestedList) {
            if (ni.isInteger()) {
                vals.push_back(ni.getInteger());
            } else {
                flatten(ni.getList());
            }
        }
    }
};
